<?php
 namespace WPAICG\AutoGPT\Ajax; use WP_Error; require_once __DIR__ . '/actions/run-now/methods.php'; if (!defined('ABSPATH')) { exit; } class AIPKit_Run_Automated_Task_Now_Action extends AIPKit_Automated_Task_Base_Ajax_Action { public function handle_request() { $task_or_error = Actions\RunNow\validate_task_and_permissions_logic($this); if (is_wp_error($task_or_error)) { $this->send_wp_error($task_or_error); return; } $task = $task_or_error; $task_id = (int)$task['id']; $task_config = json_decode($task['task_config'], true) ?: []; $task_type = $task['task_type']; switch (true) { case $task_type === 'content_indexing': Actions\RunNow\run_now_content_indexing_logic($task_id, $task_config); break; case str_starts_with($task_type, 'content_writing'): $result = Actions\RunNow\run_now_content_writing_logic($task_id, $task_config); if (is_wp_error($result)) { $this->send_wp_error($result); return; } break; case $task_type === 'community_reply_comments': Actions\RunNow\run_now_comment_reply_logic($task_id, $task_config, $task['last_run_time']); break; case $task_type === 'enhance_existing_content': Actions\RunNow\run_now_content_enhancement_logic($task_id, $task_config); break; default: $this->send_wp_error(new WP_Error('unsupported_task_type_run_now', __('This task type does not support "Run Now".', 'gpt3-ai-content-generator')), 400); return; } Actions\RunNow\finalize_run_now_task_logic($task_id); wp_send_json_success(['message' => __('Task run initiated. Check queue for progress.', 'gpt3-ai-content-generator')]); } } 